	for (int i = 1; i <= n; ++i) {

		fac[i] = fac[i - 1] * i % MOD;

	}

	ifac[n] = inverse(fac[n]);

	for (int i = n; i >= 1; --i) {

		ifac[i - 1] = ifac[i] * i % MOD;

